phase1.code:
#include <iostream>
#include <string>

// --- Base case for recursion ---
void printAll() {
    // Do nothing (end of recursion)
}

// --- Variadic template function ---
template <typename T, typename... Args>
void printAll(T first, Args... args) {
    std::cout << first;
    if (sizeof...(args) > 0) {
        std::cout << ", ";
    }
    printAll(args...);  // Recursive call
}

// --- Variadic template with newline ---
template <typename... Args>
void println(Args... args) {
    printAll(args...);
    std::cout << std::endl;
}

// --- Variadic template for summing ---
int sum() {
    return 0;
}

template <typename T, typename... Args>
T sum(T first, Args... args) {
    return first + sum(args...);
}

// --- Variadic template for multiple types ---
template <typename... Args>
void log(const std::string& prefix, Args... args) {
    std::cout << prefix << ": ";
    printAll(args...);
    std::cout << std::endl;
}

// --- Game use: create a player with variable stats ---
template <typename... Stats>
void createPlayer(const std::string& name, Stats... stats) {
    std::cout << "🎮 Creating player: " << name << std::endl;
    std::cout << "Stats: ";
    printAll(stats...);
    std::cout << std::endl;
}

// --- Fold expressions (C++17) ---
template <typename... Args>
int sumFold(Args... args) {
    return (args + ...);  // Fold expression
}

template <typename... Args>
void printFold(Args... args) {
    (std::cout << ... << args) << std::endl;  // Fold expression
}

// --- Variadic template for tuple-like storage ---
template <typename... Types>
struct GameData {
    std::tuple<Types...> data;

    GameData(Types... values) : data(values...) {}

    void display() {
        std::cout << "GameData: ";
        std::apply([](auto... vals) {
            ((std::cout << vals << " "), ...);
        }, data);
        std::cout << std::endl;
    }
};

int main() {
    std::cout << "=== Variadic Templates ===" << std::endl;

    // 1. Basic variadic function
    std::cout << "\n--- printAll ---" << std::endl;
    printAll(1, 2, 3);
    std::cout << std::endl;

    printAll("Hello", 42, 3.14, "World");
    std::cout << std::endl;

    // 2. println (with newline)
    std::cout << "\n--- println ---" << std::endl;
    println("This", "is", "a", "variadic", "template!");
    println(100, 200, 300, 400);

    // 3. Sum
    std::cout << "\n--- Sum ---" << std::endl;
    std::cout << "sum(1,2,3) = " << sum(1, 2, 3) << std::endl;
    std::cout << "sum(10,20,30,40) = " << sum(10, 20, 30, 40) << std::endl;

    // 4. Log with prefix
    std::cout << "\n--- Log ---" << std::endl;
    log("INFO", "Game", "started", "successfully");
    log("ERROR", "Failed", "to", "load", "texture");

    // 5. Game use
    std::cout << "\n--- Game: Create Player ---" << std::endl;
    createPlayer("Hero", 100, 20, 15);  // HP, ATK, DEF
    createPlayer("Mage", 80, 15, 10, 50);  // HP, ATK, DEF, MANA

    // 6. Fold expressions (C++17)
    std::cout << "\n--- Fold Expressions ---" << std::endl;
    std::cout << "sumFold(1,2,3,4,5) = " << sumFold(1, 2, 3, 4, 5) << std::endl;

    std::cout << "printFold: ";
    printFold(1, 2, "Hello", 3.14);

    // 7. GameData with tuple
    std::cout << "\n--- GameData (tuple-like) ---" << std::endl;
    GameData<int, std::string, double> playerData(42, "Hero", 3.75);
    playerData.display();

    std::cout << "\n--- Variadic Templates Summary ---" << std::endl;
    std::cout << "✅ Accept any number of arguments" << std::endl;
    std::cout << "✅ Type-safe at compile time" << std::endl;
    std::cout << "✅ Used in: logging, math, game systems" << std::endl;
    std::cout << "✅ C++17 fold expressions make them even better" << std::endl;

    return 0;
}

