#include <iostream>
#include <string>

// Base case
int addAll() {
    return 0;
}

// Recursive case
template <typename T, typename... Args>
T addAll(T first, Args... args) {
    return first + addAll(args...);
}

// logMessage using recursion
void logMessage(const std::string& prefix) {
    std::cout << prefix << std::endl;
}

template <typename T, typename... Args>
void logMessage(const std::string& prefix, T first, Args... args) {
    std::cout << prefix << ": " << first;
    if (sizeof...(args) > 0) {
        std::cout << ", ";
        logMessage("", args...);
    } else {
        std::cout << std::endl;
    }
}

int main() {
    std::cout << "=== Variadic Templates ===" << std::endl;

    std::cout << "addAll(1, 2, 3, 4, 5) = " << addAll(1, 2, 3, 4, 5) << std::endl;
    std::cout << "addAll(10, 20) = " << addAll(10, 20) << std::endl;

    logMessage("INFO", "Game", "loaded", 42, 3.14);
    logMessage("WARN", "Low", "health");

    return 0;
}
